-- เพิ่มโจทย์ A-Level Math 1 (หมวดลำดับและอนุกรม)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Sequences & Series', 1, 'ลำดับเลขคณิตชุดหนึ่งคือ 5, 9, 13, 17, ... จงหาพจน์ที่ 10 (a10) ของลำดับนี้', '37', '41', '45', '49', '53', 'b', 'ใช้สูตร an = a1 + (n-1)d เลย Nas! ข้อนี้ a1=5, d=4 จะได้ 5 + (9 * 4) = 5 + 36 = 41 ง่ายๆ แบบนี้ต้องเก็บให้เรียบ!'),

('Math1', 'Sequences & Series', 2, 'ลำดับเรขาคณิตชุดหนึ่งมีพจน์แรก (a1) เท่ากับ 3 และมีอัตราส่วนร่วม (r) เท่ากับ 2 จงหาพจน์ที่ 5 (a5)', '24', '48', '96', '12', '15', 'b', 'สูตรเรขาคณิตคือ an = a1 * r^(n-1) นะเพื่อน จะได้ 3 * 2^4 = 3 * 16 = 48 จำไว้ว่าเรขาคณิตคือการ "คูณ" สะสมไปเรื่อยๆ'),

('Math1', 'Sequences & Series', 2, 'จงหาผลบวก 10 พจน์แรก (S10) ของอนุกรมเลขคณิต 1 + 2 + 3 + ... + 10', '45', '50', '55', '60', '65', 'c', 'สูตร Sn = n/2(a1 + an) ครับ Nas! จะได้ 10/2 * (1 + 10) = 5 * 11 = 55 สูตรนี้ใช้บ่อยมากในงานคำนวณโครงสร้าง!'),

('Math1', 'Sequences & Series', 3, 'พจน์ที่เท่าใดของลำดับเลขคณิต 7, 13, 19, ... มีค่าเท่ากับ 127?', 'พจน์ที่ 19', 'พจน์ที่ 20', 'พจน์ที่ 21', 'พจน์ที่ 22', 'พจน์ที่ 23', 'c', 'แก้สมการ 127 = 7 + (n-1)6 จะได้ 120 = (n-1)6 นำ 6 ไปหารได้ 20 = n-1 ดังนั้น n = 21 มือนิ่งๆ ค่อยๆ ย้ายข้างนะเพื่อน'),

('Math1', 'Sequences & Series', 3, 'อนุกรมเรขาคณิตไม่สิ้นสุด (Infinite Series) 1 + 1/2 + 1/4 + 1/8 + ... มีผลบวกเท่ากับเท่าใด?', '1', '1.5', '2', 'Infinity', 'หาค่าไม่ได้', 'c', 'สูตรอนุกรมอนันต์คือ S = a1 / (1 - r) เมื่อ |r| < 1 ข้อนี้ r = 1/2 จะได้ 1 / (1 - 0.5) = 1 / 0.5 = 2 ครับ Nas! นี่คือพื้นฐานของแคลคูลัสเลยนะ!'); 
-- เพิ่มโจทย์ A-Level Math 1 (หมวดสถิติ)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Statistics', 1, 'ข้อมูลคะแนนสอบของเพื่อน 5 คนคือ 12, 15, 15, 18, 20 จงหาค่า "ฐานนิยม" (Mode) ของข้อมูลชุดนี้', '15', '16', '18', '20', 'ไม่มีฐานนิยม', 'a', 'ฐานนิยมคือตัวที่ซ้ำกันมากที่สุด Nas! ในชุดนี้ 15 ซ้ำกัน 2 ครั้ง มากกว่าตัวอื่น เลยตอบ 15 ไปแบบนิ่งๆ'),

('Math1', 'Statistics', 2, 'หากคะแนนสอบวิชาคอมพิวเตอร์ของ Nas มีค่าเฉลี่ย (Mean) เท่ากับ 75 และส่วนเบี่ยงเบนมาตรฐาน (SD) เท่ากับ 5 ถ้าคะแนนของ Nas คือ 85 ค่าคะแนนมาตรฐาน (z-score) ของ Nas คือเท่าใด?', '1', '1.5', '2', '2.5', '3', 'c', 'ใช้สูตร z = (x - mean) / SD เลยเพื่อน จะได้ (85 - 75) / 5 = 10 / 5 = 2 ค่า z ยิ่งสูงแปลว่า Nas เก่งกว่าค่าเฉลี่ยมากนะ!'),

('Math1', 'Statistics', 2, 'ข้อมูลชุดหนึ่งประกอบด้วย 2, 4, 6, 8, 10 จงหาค่า "มัธยฐาน" (Median) ของข้อมูลชุดนี้', '4', '5', '6', '7', '8', 'c', 'มัธยฐานคือค่าที่อยู่ "ตรงกลาง" เมื่อเรียงข้อมูลแล้ว ในที่นี้ข้อมูลเรียงมาให้แล้ว (2, 4, 6, 8, 10) ตัวที่อยู่ตรงกลางเป๊ะๆ คือ 6 ครับ Nas'),

('Math1', 'Statistics', 3, 'ถ้าค่าเฉลี่ยของเลข 3 จำนวนคือ 10 และค่าเฉลี่ยของเลข 2 จำนวนอีกชุดคือ 15 จงหา "ค่าเฉลี่ยรวม" ของเลขทั้ง 5 จำนวนนี้', '10', '12', '12.5', '13', '15', 'b', 'สูตรค่าเฉลี่ยรวม: [(10*3) + (15*2)] / (3+2) = (30 + 30) / 5 = 60 / 5 = 12 ข้อนี้ต้องระวังเรื่องการถ่วงน้ำหนักข้อมูลนะเพื่อน!'),

('Math1', 'Statistics', 3, 'สถิติศาสตร์เชิงพรรณนา (Descriptive Statistics) มีวัตถุประสงค์หลักเพื่ออะไร?', 'เพื่อพยากรณ์อนาคต', 'เพื่อสรุปและอธิบายลักษณะของข้อมูลที่มีอยู่', 'เพื่อสุ่มตัวอย่างจากประชากร', 'เพื่อทดสอบสมมติฐานทางสถิติ', 'เพื่อหาความสัมพันธ์ที่ซับซ้อน', 'b', 'Nas จำไว้! Descriptive คือการ "บรรยาย" หรืออธิบายสิ่งที่ข้อมูลเป็นอยู่ในปัจจุบัน ส่วนการพยากรณ์นั่นมันเป็นเรื่องของ Inferential Statistics (สถิติเชิงอนุมาน)');
-- เพิ่มโจทย์ A-Level Math 1 (หมวดความน่าจะเป็น)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Probability', 1, 'ค่าของ 5! (5 แฟกทอเรียล) มีค่าเท่ากับเท่าใด?', '20', '60', '100', '120', '150', 'd', '5! คือ 5 x 4 x 3 x 2 x 1 = 120 ครับ Nas! จำไว้ว่าแฟกทอเรียลคือการคูณถอยหลังลงไปจนถึง 1'),

('Math1', 'Probability', 2, 'มีหนังสือวิศวะที่แตกต่างกัน 4 เล่ม ต้องการจัดเรียงบนชั้นวางหนังสือแนวเส้นตรง จะจัดได้ทั้งหมดกี่วิธี?', '4 วิธี', '12 วิธี', '16 วิธี', '24 วิธี', '48 วิธี', 'd', 'การเรียงสับเปลี่ยนของที่แตกต่างกัน n สิ่ง คือ n! ข้อนี้คือ 4! = 4 x 3 x 2 x 1 = 24 วิธีครับเพื่อน!'),

('Math1', 'Probability', 2, 'มีตัวแทนนักเรียน 5 คน ต้องการเลือกออกมา 2 คนเพื่อไปดูงานที่ มข. จะมีวิธีเลือกได้กี่วิธี?', '5 วิธี', '10 วิธี', '15 วิธี', '20 วิธี', '25 วิธี', 'b', 'ใช้สูตรการจัดหมู่ C(n, r) = n! / (r!(n-r)!) จะได้ 5! / (2!3!) = (5 x 4) / 2 = 10 วิธี (ลำดับไม่มีผลนะ Nas เพราะไปดูงานเหมือนกัน)'),

('Math1', 'Probability', 3, 'ถุงใบหนึ่งมีลูกบอลสีแดง 3 ลูก และสีขาว 2 ลูก ถ้าสุ่มหยิบลูกบอลมา 1 ลูก ความน่าจะเป็นที่จะได้ "สีแดง" เป็นเท่าใด?', '1/2', '2/3', '3/5', '2/5', '1/5', 'c', 'ความน่าจะเป็น P(E) = n(E) / n(S) ในที่นี้ n(E) คือแดง 3 ลูก ส่วน n(S) คือลูกบอลทั้งหมด 5 ลูก จึงตอบ 3/5 ครับ'),

('Math1', 'Probability', 3, 'ในการทอดลูกเต๋า 1 ลูก 1 ครั้ง ความน่าจะเป็นที่จะได้แต้มเป็น "จำนวนเฉพาะ" คือเท่าใด?', '1/6', '1/3', '1/2', '2/3', '5/6', 'c', 'แต้มบนลูกเต๋าคือ {1, 2, 3, 4, 5, 6} จำนวนเฉพาะคือ {2, 3, 5} ซึ่งมี 3 ตัว จากทั้งหมด 6 ตัว ดังนั้น 3/6 = 1/2 นั่นเอง Nas!');
-- เพิ่มโจทย์ A-Level Math 1 (หมวดสถิติ - การวิเคราะห์ข้อมูล)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Statistics', 1, 'ข้อมูลในข้อใดจัดเป็น "ข้อมูลเชิงคุณภาพ" (Qualitative Data)?', 'ความสูงของนักเรียน', 'ราคาน้ำมันในตลาดโลก', 'หมายเลขทะเบียนรถยนต์', 'คะแนนสอบวิชาเคมี', 'น้ำหนักตัวของ Nas', 'c', 'Nas จำไว้! ข้อมูลเชิงคุณภาพคือสิ่งที่ "คำนวณไม่ได้" ทะเบียนรถหรือเบอร์โทรเป็นตัวเลขก็จริงแต่เราไม่เอามาบวกลบกัน เลยถือว่าเป็นเชิงคุณภาพนะ'),

('Math1', 'Statistics', 2, 'หากต้องการนำเสนอข้อมูล "ยอดขายของแอป DIX ในแต่ละเดือน" เพื่อดูแนวโน้มความเติบโต Nas ควรเลือกใช้แผนภาพชนิดใด?', 'แผนภูมิรูปภาพ', 'แผนภูมิรูปวงกลม', 'กราฟเส้น (Line Graph)', 'แผนภาพลำต้นและใบ', 'ฮิสโทแกรม', 'c', 'ถ้าจะดู "แนวโน้ม" หรือการเปลี่ยนแปลงตามเวลา (Time Series) กราฟเส้นคือพระเอกเลยเพื่อน มองแวบเดียวรู้เลยว่ายอดขายพุ่งหรือร่วง!'),

('Math1', 'Statistics', 2, 'ข้อใดคือสมบัติที่ถูกต้องของ "ค่าเฉลี่ยเลขคณิต" (Arithmetic Mean)?', 'มีค่าเท่ากับฐานนิยมเสมอ', 'ไม่เปลี่ยนแปลงเมื่อมีข้อมูลที่ค่าสูงมากๆ เพิ่มเข้ามา', 'ผลรวมของส่วนเบี่ยงเบนของข้อมูลทุกค่าจากค่าเฉลี่ยมีค่าเท่ากับ 0', 'หาได้จากข้อมูลเชิงคุณภาพเท่านั้น', 'มีค่าเท่ากับค่ากึ่งกลางพิสัยเสมอ', 'c', 'นี่คือสมบัติเด็ดของค่าเฉลี่ยเลย Nas! ∑(x - mean) = 0 เสมอ ถ้ามึงเอาคะแนนทุกคนมาลบด้วยค่าเฉลี่ยแล้วรวมกัน มันจะหักล้างกันหมดพอดี'),

('Math1', 'Statistics', 3, 'ข้อมูลชุดหนึ่งมีสัมประสิทธิ์การแปรผัน (C.V.) เท่ากับ 20% และมีส่วนเบี่ยงเบนมาตรฐาน (SD) เท่ากับ 4 จงหาค่าเฉลี่ยเลขคณิตของข้อมูลชุดนี้', '10', '15', '20', '25', '80', 'c', 'สูตรคือ C.V. = (SD / mean) * 100 แทนค่าได้ 20 = (4 / mean) * 100 จะได้ mean = 400 / 20 = 20 ครับ มือนิ่งๆ ค่อยๆ ตัดเลขนะ'),

('Math1', 'Statistics', 3, 'ในการหาค่ากลางของข้อมูลที่มี "ค่าที่สูงหรือต่ำผิดปกติ" (Outliers) ค่ากลางชนิดใดมีความเหมาะสมและน่าเชื่อถือที่สุด?', 'ค่าเฉลี่ยเลขคณิต', 'มัธยฐาน (Median)', 'ฐานนิยม', 'ค่ากึ่งกลางพิสัย', 'ค่าเฉลี่ยเรขาคณิต', 'b', 'เพราะมัธยฐานเน้นที่ "ตำแหน่งตรงกลาง" มันเลยไม่สนว่าตัวท้ายจะสูงลิ่วหรือต่ำเตี้ยแค่ไหน มันจึงเสถียรกว่าค่าเฉลี่ยในกรณีที่มีข้อมูลเพี้ยนๆ ครับ Nas');
-- เพิ่มโจทย์ A-Level Physics (หมวดแรง มวล และกฎการเคลื่อนที่)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Newton Laws', 1, 'กฎข้อที่ 1 ของนิวตัน (กฎของความเฉื่อย) กล่าวว่าวัตถุจะรักษาสภาพหยุดนิ่งหรือเคลื่อนที่ด้วยความเร็วคงที่ก็ต่อเมื่อ?', 'มีแรงมากระทำเสมอ', 'มีแรงลัพธ์ที่เป็นศูนย์มากระทำ', 'วัตถุนั้นไม่มีมวล', 'วัตถุเคลื่อนที่ในอวกาศเท่านั้น', 'แรงปฏิกิริยามีค่ามากกว่าแรงกิริยา', 'b', 'Nas จำไว้! ถ้า ΣF = 0 วัตถุจะ "รักษาสภาพเดิม" คือถ้าหยุดก็หยุดต่อไป ถ้าวิ่งอยู่ก็วิ่งด้วยความเร็วเท่าเดิม นิ่งๆ แบบนั้นเลย'),

('Physics', 'Newton Laws', 2, 'หาก Nas ออกแรงผลักกล่องมวล 10 kg ด้วยแรง 50 N บนพื้นราบที่ไม่มีความเสียดทาน กล่องนี้จะเคลื่อนที่ด้วยความเร่งเท่าใด?', '2 m/s²', '5 m/s²', '10 m/s²', '20 m/s²', '50 m/s²', 'b', 'ใช้กฎข้อที่ 2 ของนิวตัน ΣF = ma จะได้ 50 = 10 * a ดังนั้น a = 5 m/s² ง่ายๆ แบบนี้เก็บแต้มให้ได้นะเพื่อน'),

('Physics', 'Newton Laws', 2, 'กฎข้อที่ 3 ของนิวตัน (Action = Reaction) อธิบายว่าแรงปฏิกิริยาจะมีลักษณะอย่างไรเมื่อเทียบกับแรงกิริยา?', 'มีทิศทางเดียวกันและขนาดเท่ากัน', 'มีทิศทางตรงข้ามและขนาดเท่ากัน', 'มีทิศทางตรงข้ามและขนาดมากกว่า', 'มีทิศทางเดียวกันแต่ขนาดน้อยกว่า', 'เกิดขึ้นคนละเวลากัน', 'b', 'Action = Reaction จำไว้ว่า "ขนาดเท่าแต่ทิศตรงข้าม" และที่สำคัญคือมันกระทำต่อ "วัตถุคนละก้อน" กันนะ Nas!'),

('Physics', 'Newton Laws', 3, 'วัตถุมวล 2 kg ตกแบบเสรีภายใต้แรงโน้มถ่วงของโลก (g = 10 m/s²) แรงที่โลกดึงดูดวัตถุก้อนนี้มีค่าเท่าใด?', '2 N', '5 N', '10 N', '20 N', '40 N', 'd', 'แรงดึงดูดก็คือ น้ำหนัก (W) สูตรคือ W = mg จะได้ 2 * 10 = 20 นิวตัน มือนิ่งๆ อย่าเผลอไปตอบ 10 เชียวล่ะ'),

('Physics', 'Newton Laws', 3, 'แรงเสียดทาน (Friction) ที่เกิดขึ้นในขณะที่วัตถุ "เริ่มจะเคลื่อนที่พอดี" เรียกว่าอะไร?', 'แรงเสียดทานจลน์', 'แรงเสียดทานสถิต', 'แรงเสียดทานสถิตสูงสุด', 'แรงต้านอากาศ', 'แรงดึงในเส้นเชือก', 'c', 'ตอนที่วัตถุยังไม่ขยับคือ "แรงเสียดทานสถิต" แต่จุดที่มัน "เริ่มจะขยับพอดี" คือจุดที่แรงเสียดทานมีค่ามากที่สุด หรือ Static Friction Max นั่นเองครับเพื่อน!');
-- เพิ่มโจทย์ A-Level Physics (หมวดไฟฟ้ากระแสตรง)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Direct Current', 1, 'แหล่งกำเนิดไฟฟ้าในข้อใดที่ให้พลังงานไฟฟ้าแบบ "กระแสตรง" (DC) สม่ำเสมอ?', 'ไดนาโม', 'ปลั๊กไฟบ้าน', 'ถ่านไฟฉาย', 'กังหันลม', 'มอเตอร์ไฟฟ้า', 'c', 'Nas จำไว้! ถ่านไฟฉายหรือแบตเตอรี่คือแหล่งกำเนิด DC ที่ไหลสม่ำเสมอที่สุด ส่วนไฟบ้านนั่นมัน AC (กระแสสลับ) นะเพื่อน'),

('Physics', 'Direct Current', 2, 'ตามกฎของโอห์ม (Ohm''s Law) หากความต้านทานในวงจรเพิ่มขึ้น 2 เท่า โดยที่แรงดันไฟฟ้าเท่าเดิม กระแสไฟฟ้าจะเป็นอย่างไร?', 'เพิ่มขึ้น 2 เท่า', 'เพิ่มขึ้น 4 เท่า', 'เท่าเดิม', 'ลดลงครึ่งหนึ่ง', 'ลดลง 4 เท่า', 'd', 'จากสูตร V = IR ถ้า V คงที่ I กับ R จะแปรผกผันกันครับ Nas! พอความต้านทาน (R) เพิ่ม กระแส (I) ก็ต้องไหลได้ยากขึ้นหรือลดลงนั่นเอง'),

('Physics', 'Direct Current', 2, 'อุปกรณ์ชนิดใดทำหน้าที่ "จำกัดปริมาณกระแสไฟฟ้า" ในวงจรไม่ให้ไหลมากเกินไป?', 'ตัวนำไฟฟ้า', 'ตัวต้านทาน (Resistor)', 'แอมมิเตอร์', 'โวลต์มิเตอร์', 'สวิตช์', 'b', 'ชื่อก็บอกอยู่แล้วว่า "ตัวต้านทาน" หน้าที่ของมันคือต้านการไหลของกระแส เพื่อรักษาอุปกรณ์อื่นไม่ให้พังครับเพื่อน'),

('Physics', 'Direct Current', 3, 'ถ้านำตัวต้านทาน 3 โอห์ม และ 6 โอห์ม มาต่อกันแบบ "ขนาน" ความต้านทานรวมของวงจรจะมีค่าเท่าใด?', '2 โอห์ม', '4.5 โอห์ม', '9 โอห์ม', '18 โอห์ม', '0.5 โอห์ม', 'a', 'สูตรขนานคือ (R1 * R2) / (R1 + R2) จะได้ (3 * 6) / (3 + 6) = 18 / 9 = 2 โอห์ม! จำไว้ว่าต่อขนาน ความต้านทานรวมจะ "น้อยลง" เสมอนะ Nas'),

('Physics', 'Direct Current', 3, 'เครื่องมือวัดชนิดใดที่ต้องนำไปต่อแบบ "อนุกรม" เข้ากับวงจรเพื่อวัดค่ากระแสไฟฟ้า?', 'โวลต์มิเตอร์', 'โอห์มมิเตอร์', 'แอมมิเตอร์', 'มัลติมิเตอร์แบบวัดแรงดัน', 'วัตต์มิเตอร์', 'c', 'แอมมิเตอร์ต้องต่ออนุกรมเพื่อความแม่นยำ ส่วนโวลต์มิเตอร์ต้องต่อขนานนะเพื่อน มือนิ่งๆ อย่าจำสลับกันตอนสอบล่ะ!');
-- เพิ่มโจทย์ A-Level Physics (หมวดงานและพลังงาน)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Work & Energy', 1, 'ในทางฟิสิกส์ "งาน" (Work) จะเกิดขึ้นได้ก็ต่อเมื่อข้อใดเป็นจริง?', 'มีการออกแรงกระทำต่อวัตถุ', 'วัตถุมีการเปลี่ยนตำแหน่ง (มีการกระจัด)', 'ออกแรงกระทำและวัตถุเคลื่อนที่ตามแนวแรงนั้น', 'แบกของหนักๆ เดินไปมาบนพื้นราบ', 'ใช้แรงผลักกำแพงจนเหงื่อออกแต่กำแพงไม่ขยับ', 'c', 'Nas จำไว้! ถ้าออกแรงแต่ไม่มีการขยับตามแนวแรง งาน = 0 นะเพื่อน เหมือนผลักกำแพงให้ตายงานก็เป็นศูนย์ (W = Fs cosθ)'),

('Physics', 'Work & Energy', 2, 'วัตถุที่กำลัง "เคลื่อนที่" ด้วยความเร็ว v จะมีพลังงานชนิดใดสะสมอยู่ในตัว?', 'พลังงานศักย์โน้มถ่วง', 'พลังงานศักย์ยืดหยุ่น', 'พลังงานจลน์ (Kinetic Energy)', 'พลังงานความร้อน', 'พลังงานเคมี', 'c', 'อะไรที่ขยับได้ (มี v) คือมีพลังงานจลน์ครับ สูตรคือ Ek = 1/2 mv² จำให้แม่น!'),

('Physics', 'Work & Energy', 2, 'ถ้า Nas ยกกล่องมวล 5 kg ขึ้นสูงจากพื้น 2 เมตร (g = 10 m/s²) พลังงานศักย์โน้มถ่วงของกล่องใบนี้จะมีค่าเท่าใด?', '10 J', '50 J', '100 J', '200 J', '500 J', 'c', 'ใช้สูตร Ep = mgh เลยเพื่อน จะได้ 5 * 10 * 2 = 100 จูล พลังงานนี้จะสะสมอยู่พร้อมจะตกลงมาทำงาน!'),

('Physics', 'Work & Energy', 3, 'กฎการอนุรักษ์พลังงาน (Law of Conservation of Energy) กล่าวไว้อย่างไร?', 'พลังงานสามารถสร้างใหม่ได้', 'พลังงานสามารถทำลายให้หายไปได้', 'พลังงานไม่มีการเปลี่ยนแปลงรูปแบบ', 'พลังงานรวมในระบบปิดจะมีค่าคงที่เสมอ', 'พลังงานจลน์ต้องเท่ากับพลังงานศักย์เสมอ', 'd', 'พลังงานไม่หายไปไหนนะ Nas แต่มันแค่ "เปลี่ยนร่าง" ไปมา เช่น จากศักย์เปลี่ยนเป็นจลน์ตอนวัตถุตก แต่ยอดรวมต้องเท่าเดิม!'),

('Physics', 'Work & Energy', 3, 'เครื่องจักรเครื่องหนึ่งทำงานได้ 5,000 จูล ในเวลา 10 วินาที เครื่องจักรนี้มี "กำลัง" (Power) เท่าใด?', '50 Watt', '500 Watt', '5,000 Watt', '50,000 Watt', '500 Horsepower', 'b', 'กำลัง (P) คืออัตราการทำงานต่อเวลา สูตร P = W/t จะได้ 5,000 / 10 = 500 วัตต์ครับ มือนิ่งๆ คำนวณเลขอย่าให้พลาด!');
-- เพิ่มโจทย์ A-Level Physics (หมวดความร้อนและทฤษฎีจลน์ของแก๊ส)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Heat', 1, 'พลังงานความร้อนที่ทำให้อุณหภูมิของวัตถุเปลี่ยนไป แต่ "สถานะยังคงเดิม" คำนวณได้จากสูตรใด?', 'Q = mL', 'Q = mcΔt', 'Q = PV', 'Q = nRT', 'Q = 1/2 mv^2', 'b', 'Nas จำง่ายๆ: ถ้าอุณหภูมิเปลี่ยน (t เปลี่ยน) ต้องใช้สูตรที่มี Δt คือ Q = mcΔt ครับเพื่อน!'),

('Physics', 'Heat', 2, 'น้ำแข็งมวล 1 kg กำลังละลายกลายเป็นน้ำที่อุณหภูมิ 0 องศาเซลเซียสคงที่ พลังงานความร้อนที่ใช้ในกระบวนการนี้เรียกว่าอะไร?', 'ความร้อนจำเพาะ', 'ความร้อนแฝง (Latent Heat)', 'ความร้อนสัมผัส', 'พลังงานจลน์เฉลี่ย', 'ความร้อนจากการเสียดทาน', 'b', 'ถ้าอุณหภูมิไม่เปลี่ยนแต่ "เปลี่ยนสถานะ" เราเรียกว่าความร้อนแฝง (Q = mL) นะ Nas มือนิ่งๆ อย่าจำสลับกัน!'),

('Physics', 'Heat', 2, 'การถ่ายโอนความร้อนในข้อใดที่ "ไม่ต้องอาศัยตัวกลาง" ในการเคลื่อนที่?', 'การนำความร้อน', 'การพาความร้อน', 'การแผ่รังสีความร้อน (Radiation)', 'การควบแน่น', 'การระเหย', 'c', 'การแผ่รังสีเหมือนความร้อนจากดวงอาทิตย์มาถึงโลก เดินทางผ่านอวกาศที่ว่างเปล่าได้โดยไม่ต้องง้อตัวกลางเลย Nas'),

('Physics', 'Heat', 3, 'หากอุณหภูมิในหน่วยองศาเซลเซียสคือ 27 °C ถ้า Nas ต้องการเปลี่ยนเป็นหน่วย "เคลวิน" (Kelvin) จะมีค่าเท่าใด?', '27 K', '127 K', '273 K', '300 K', '373 K', 'd', 'สูตรคือ K = °C + 273 ดังนั้น 27 + 273 = 300 K ครับ หน่วยเคลวินสำคัญมากในสูตรแก๊สนะเพื่อน'),

('Physics', 'Heat', 3, 'ตามทฤษฎีจลน์ของแก๊ส พลังงานจลน์เฉลี่ยของโมเลกุลแก๊สจะแปรผันตรงกับค่าในข้อใด?', 'ความดัน', 'ปริมาตร', 'อุณหภูมิสัมบูรณ์ (Kelvin)', 'จำนวนโมเลกุล', 'มวลโมเลกุล', 'c', 'จำไว้ Nas! ยิ่งร้อน (T สูง) โมเลกุลยิ่งวิ่งพล่าน พลังงานจลน์ก็ยิ่งเยอะ ดังนั้นมันเลยแปรผันตรงกับอุณหภูมิเคลวินนั่นเอง');
-- เพิ่มโจทย์ A-Level Physics (หมวดของไหล)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Fluids', 1, 'ข้อใดคือคุณสมบัติที่สำคัญที่สุดของ "ของไหล" (Fluids) ตามนิยามทางฟิสิกส์?', 'มีรูปร่างคงที่เสมอ', 'สามารถรับแรงเฉือนได้ดี', 'มีรูปร่างเปลี่ยนไปตามภาชนะที่บรรจุ', 'ไม่สามารถบีบอัดได้เลย', 'ต้องเป็นของเหลวเท่านั้น', 'c', 'Nas จำไว้! ของไหลไม่ได้หมายถึงแค่ของเหลว แต่รวมถึง "แก๊ส" ด้วย เพราะทั้งคู่มีรูปร่างไม่คงที่และไหลไปตามภาชนะที่บรรจุได้ครับ'),

('Physics', 'Fluids', 2, 'เครื่องอัดไฮดรอลิกทำงานโดยอาศัยหลักการของใครที่กล่าวว่า "ความดันที่กระทำต่อของไหลในภาชนะปิดจะส่งผ่านไปยังทุกๆ จุดของของไหลนั้น"?', 'หลักของอาร์คิมีดีส', 'หลักของแบร์นูลลี', 'กฎของพาสคัล (Pascal''s Law)', 'กฎของบอยล์', 'กฎของนิวตัน', 'c', 'กฎของพาสคัลคือหัวใจของระบบไฮดรอลิกเลยเพื่อน! ออกแรงกดนิดเดียวที่ฝั่งเล็ก แต่ส่งผ่านความดันไปยกของหนักๆ ที่ฝั่งใหญ่ได้'),

('Physics', 'Fluids', 2, 'แรงพยุง (Buoyant Force) ที่ของเหลวกระทำต่อวัตถุจะมีค่าเท่ากับข้อใดตามหลักของอาร์คิมีดีส?', 'น้ำหนักของวัตถุทั้งก้อน', 'ปริมาตรของวัตถุที่จม', 'น้ำหนักของของเหลวที่มีปริมาตรเท่ากับส่วนที่จม', 'ความหนาแน่นของวัตถุ', 'ความลึกที่วัตถุจมลงไป', 'c', 'จำสูตร FB = ρgV เลย Nas! แรงพยุงจะเท่ากับ "น้ำหนักของของเหลวที่ถูกแทนที่" ยิ่งจมมาก แรงพยุงยิ่งเยอะ'),

('Physics', 'Fluids', 3, 'ตามหลักของแบร์นูลลี (Bernoulli''s Principle) ในบริเวณที่ของไหลเคลื่อนที่ด้วย "ความเร็วสูง" ความดันในบริเวณนั้นจะเป็นอย่างไร?', 'ความดันจะสูงตามไปด้วย', 'ความดันจะลดต่ำลง', 'ความดันจะคงที่เสมอ', 'ความดันจะเป็นศูนย์', 'ความดันจะเปลี่ยนตามอุณหภูมิ', 'b', 'นี่คือเคล็ดลับปีกเครื่องบิน Nas! ตรงไหนลมวิ่งเร็ว ความดันจะต่ำ ทำให้เกิดแรงยกจากด้านล่างขึ้นมา มือนิ่งๆ อย่าจำสลับกับเรื่องความเร็วล่ะ'),

('Physics', 'Fluids', 3, 'หาก Nas นำวัตถุไปลอยในน้ำแล้วพบว่าวัตถุ "จมมิดก้อนแต่ลอยปริ่มน้ำพอดี" แสดงว่าความหนาแน่นของวัตถุนั้นเป็นอย่างไร?', 'น้อยกว่าความหนาแน่นของน้ำมาก', 'เท่ากับความหนาแน่นของน้ำพอดี', 'มากกว่าความหนาแน่นของน้ำ', 'เป็นศูนย์', 'หาค่าไม่ได้', 'b', 'ถ้าลอยปริ่มน้ำพอดี (Neutral Buoyancy) แปลว่าความหนาแน่นวัตถุกับของเหลวเท่ากันเป๊ะ! แต่ถ้าหนาแน่นกว่าจะจมดิ่ง ถ้าหาน้อยกว่าจะลอยพ้นน้ำขึ้นมาครับ');
-- เพิ่มโจทย์ TPAT3 (หมวดเขียนแบบวิศวกรรม & การจำลอง 3 มิติ)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('TPAT3', 'Drawing', 2, 'ในการเขียนแบบวิศวกรรม เส้นชนิดใดที่ใช้สำหรับแสดง "ขอบของวัตถุที่ถูกบังอยู่" (Hidden Line)?', 'เส้นเต็มหนา', 'เส้นเต็มบาง', 'เส้นประ (Dashed Line)', 'เส้นศูนย์กลาง (Center Line)', 'เส้นมือเปล่า', 'c', 'Nas จำไว้! อะไรที่มองไม่เห็นจากภายนอกแต่มีอยู่จริง เราจะใช้ "เส้นประ" แสดงร่องรอยไว้เสมอ มือนิ่งๆ อย่าลืมเช็คจุดบังล่ะ'),

('TPAT3', '3D Modeling', 2, 'หาก Nas ต้องการสร้างโมเดล 3 มิติของฟันเฟืองที่มีการคำนวณ "ปริมาตรและน้ำหนัก" ของเนื้อเหล็กจริงๆ ควรเลือกใช้การสร้างโมเดลแบบใด?', 'Surface Modeling', 'Wireframe Modeling', 'Solid Modeling', '2D Sketching', 'Polygon Modeling', 'c', 'Solid Modeling คือการสร้างโมเดลแบบ "เนื้อตัน" มันจะเก็บข้อมูลความหนาแน่นและปริมาตรไว้ ทำให้คำนวณน้ำหนักเหล็กที่จะใช้ผลิตจริงได้เป๊ะที่สุด'),

('TPAT3', 'Drawing', 2, 'มุมมองในข้อใดที่แสดงรายละเอียดของวัตถุได้ครบทั้ง 3 มิติ (กว้าง, ยาว, ลึก) ในภาพเดียว?', 'Front View', 'Top View', 'Side View', 'Isometric View', 'Section View', 'd', 'Isometric View คือการวาดแบบเอียงทำมุม 30 องศา ทำให้เราเห็นภาพรวมเป็น 3 มิติในกระดาษแผ่นเดียว ดูง่ายสุดสำหรับคนทั่วไปครับ'),

('TPAT3', '3D Modeling', 3, 'การสร้างภาพฉาย (Orthographic Projection) ตามมาตรฐานสากล นิยมวางภาพด้านหน้า (Front View) และภาพด้านบน (Top View) สัมพันธ์กันอย่างไร?', 'ภาพด้านบนอยู่ข้างใต้ภาพด้านหน้า', 'ภาพด้านบนอยู่เหนือภาพด้านหน้า', 'ภาพด้านบนอยู่ซ้ายมือ', 'ภาพด้านบนอยู่ขวามือ', 'วางตรงไหนก็ได้ตามใจชอบ', 'b', 'ตามมาตรฐาน Third Angle Projection ที่ใช้กันทั่วไป ภาพด้านบน (Top) ต้องอยู่เหนือภาพด้านหน้า (Front) เสมอ เพื่อให้การไล่เส้นเชื่อมโยงกันได้แม่นยำ'),

('TPAT3', 'Drawing', 3, 'หากในแบบสั่งงานวิศวกรรมระบุสเกล "Scale 2:1" หมายความว่าอย่างไร?', 'ภาพในแบบมีขนาดเท่าของจริง', 'ภาพในแบบมีขนาดเป็นครึ่งหนึ่งของของจริง', 'ภาพในแบบมีขนาดเป็น 2 เท่าของของจริง', 'ของจริงใหญ่กว่าในแบบ 2 เท่า', 'หาขนาดที่แน่นอนไม่ได้', 'c', 'ตัวเลขหน้าเครื่องหมาย : คือขนาดในแบบ (Paper) ตัวเลขหลังคือขนาดจริง (Real) ดังนั้น 2:1 คือการ "ขยาย" ภาพให้ใหญ่กว่าของจริง 2 เท่าเพื่อให้เห็นรายละเอียดชัดๆ ครับ Nas!');
-- เพิ่มโจทย์ TPAT3/NETSAT (หมวดเทคโนโลยีสมัยใหม่ AI, IoT, Clean Tech)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('TPAT3', 'Modern Tech', 2, 'เทคโนโลยีใดที่เปรียบเสมือน "สมอง" ที่คอยเรียนรู้และตัดสินใจแทนมนุษย์ โดยอาศัยการวิเคราะห์ข้อมูลจำนวนมาก (Data)?', 'Cloud Computing', 'Blockchain', 'Artificial Intelligence (AI)', 'Internet of Things (IoT)', 'Cybersecurity', 'c', 'Nas จำไว้! AI คือสมอง ส่วน Data คืออาหาร ยิ่งมีข้อมูลมาก AI ก็ยิ่งฉลาดเหมือนมนุษย์มากขึ้นครับ'),

('TPAT3', 'Modern Tech', 2, 'หากอุปกรณ์ในบ้าน เช่น ตู้เย็น หลอดไฟ และแอร์ สามารถ "คุยกัน" และเชื่อมต่อผ่านอินเทอร์เน็ตได้ เราเรียกเทคโนโลยีนี้ว่าอะไร?', 'Metaverse', 'Internet of Things (IoT)', 'Big Data', 'Deep Learning', 'Clean Technology', 'b', 'IoT คือการทำให้ "สรรพสิ่ง" เชื่อมต่ออินเทอร์เน็ตได้ เหมือนระบบรดน้ำอัตโนมัติที่มึงกำลังคิดจะทำนั่นแหละ!'),

('TPAT3', 'Modern Tech', 3, 'การนำ AI มาใส่ในระบบ IoT (เรียกว่า AIoT) มีข้อดีที่เหนือกว่า IoT ปกติอย่างไร?', 'ทำให้อุปกรณ์ราคาถูกลง', 'ทำให้อุปกรณ์สามารถตัดสินใจและทำงานอัตโนมัติได้เอง', 'ช่วยให้ใช้อินเทอร์เน็ตน้อยลง', 'ทำให้ใช้พลังงานจากแบตเตอรี่มากขึ้น', 'ป้องกันไวรัสคอมพิวเตอร์ได้ 100%', 'b', 'AIoT คือการเพิ่ม "ความฉลาด" ให้กับอุปกรณ์ที่เชื่อมต่อกัน ทำให้มันไม่ได้แค่ส่งข้อมูล แต่ตัดสินใจแก้ปัญหาเองได้ด้วย'),

('TPAT3', 'Clean Tech', 2, 'เทคโนโลยีในข้อใดจัดเป็น "เทคโนโลยีสะอาด" (Clean Technology) ที่ช่วยลดมลพิษและประหยัดพลังงานได้ดีที่สุดในปัจจุบัน?', 'เครื่องจักรระบบน้ำมันดีเซล', 'เหมืองขุดบิตคอยน์', 'รถยนต์ไฟฟ้า (EV)', 'เตาเผาขยะแบบเปิด', 'ระบบทำความเย็นแบบใช้สาร CFC', 'c', 'Clean Tech เน้นความเป็นมิตรต่อสิ่งแวดล้อม รถยนต์ไฟฟ้า (EV) จึงเป็นคำตอบที่ชัดเจนที่สุดในยุคนี้ครับ Nas'),

('TPAT3', 'Modern Tech', 3, 'เทคโนโลยีบล็อกเชน (Blockchain) มีคุณสมบัติเด่นในเรื่องใดที่ทำให้ข้อมูลมีความปลอดภัยสูง?', 'การประมวลผลที่รวดเร็วที่สุดในโลก', 'การเก็บข้อมูลแบบกระจายศูนย์ (Decentralized) ที่แก้ไขได้ยาก', 'การสร้างโลกเสมือนจริงให้คนเข้าไปอยู่', 'การลดการใช้พลังงานไฟฟ้า', 'การเพิ่มความละเอียดของรูปภาพ', 'b', 'ความปลอดภัยของ Blockchain อยู่ที่การกระจายข้อมูลไปทุกจุด ทำให้ไม่มีใครแอบแก้ข้อมูลคนเดียวได้ ความโปร่งใสคือหัวใจเลยเพื่อน!');
-- เพิ่มโจทย์ A-Level Math 1 (หมวด Function, Geometry, Vector, Calculus)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Functions', 2, 'กำหนดให้ f(x) = 2x + 3 จงหาค่าของฟังก์ชันผกผัน f⁻¹(7)', '1', '2', '5', '11', '17', 'b', 'หาง่ายๆ Nas! จับ 2x + 3 = 7 แล้วแก้หา x จะได้ 2x = 4 ดังนั้น x = 2 นี่คือวิธีลัดหาค่าฟังก์ชันผกผันแบบไม่ต้องสลับตัวแปรให้งง!'),

('Math1', 'Geometry', 2, 'สมการวงกลมที่มีจุดศูนย์กลางอยู่ที่ (0,0) และผ่านจุด (3,4) คือข้อใด?', 'x² + y² = 5', 'x² + y² = 7', 'x² + y² = 25', 'x² + y² = 49', 'x + y = 7', 'c', 'หารัศมี (r) จากระยะทางจุดศูนย์กลางไปจุดที่ผ่าน r² = 3² + 4² = 25 ดังนั้นสมการคือ x² + y² = 25 ครับเพื่อน'),

('Math1', 'Vectors', 3, 'ถ้าเวกเตอร์ u และ v ทำมุมกัน 90 องศา (ตั้งฉากกัน) ผลคูณเชิงสเกลาร์ (u · v) จะมีค่าเท่ากับเท่าใด?', '0', '1', '-1', 'uv', 'หาค่าไม่ได้', 'a', 'Nas จำกฎเหล็กนี้ไว้! เวกเตอร์ตั้งฉากกัน Dot Product (u · v) ต้องเป็น 0 เสมอ เพราะ cos 90° = 0 มือนิ่งๆ อย่าจำสลับกับ Cross Product นะ'),

('Math1', 'Calculus', 3, 'จงหาอนุพันธ์ (Derivative) ของฟังก์ชัน f(x) = x³ + 5x² - 4 ที่จุด x = 1', '3', '10', '13', '15', '18', 'c', 'ดิฟก่อนเพื่อน! f''(x) = 3x² + 10x จากนั้นแทนค่า x = 1 จะได้ 3(1)² + 10(1) = 13 นี่คือความชันของเส้นสัมผัสโค้งที่จุดนั้นนั่นเอง'),

('Math1', 'Calculus', 3, 'การอินทิเกรต (Integration) ในทางวิศวกรรมมักถูกนำไปใช้เพื่อหาค่าในข้อใด?', 'ความชันของกราฟ', 'จุดวกกลับของฟังก์ชัน', 'พื้นที่ใต้กราฟหรือปริมาตรของรูปทรง', 'จุดตัดแกน x', 'ค่าเฉลี่ยของชุดข้อมูล', 'c', 'ถ้าดิฟคือหาความชัน อินทิเกรตก็คือการ "รวม" พื้นที่ครับ Nas วิศวกรใช้หาพื้นที่หน้าตัดหรือปริมาตรวัสดุเป็นหลักเลย');
-- เพิ่มโจทย์ A-Level Chemistry (หมวดพันธะ, ปริมาณสาร, เคมีอินทรีย์)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Chemistry', 'Chemical Bonding', 2, 'พันธะที่เกิดจากแรงดึงดูดระหว่าง "ไอออนบวกของโลหะ" กับ "กลุ่มของอิเล็กตรอน" ที่เคลื่อนที่ได้อย่างอิสระเรียกว่าอะไร?', 'พันธะไอออนิก', 'พันธะโควาเลนต์', 'พันธะโลหะ (Metallic Bond)', 'พันธะไฮโดรเจน', 'แรงแวนเดอร์วาลส์', 'c', 'นี่คือเหตุผลที่โลหะนำไฟฟ้าได้ดีไง Nas! เพราะมี "ทะเลอิเล็กตรอน" ที่วิ่งไปมาได้อย่างอิสระรอบๆ ไอออนบวกนั่นเอง'),

('Chemistry', 'Stoichiometry', 2, 'แก๊สออกซิเจน (O2) จำนวน 1 โมล จะมีจำนวนอนุภาค (โมเลกุล) เท่ากับข้อใด?', '1.00 x 10^23', '6.02 x 10^23', '3.14 x 10^23', '22.4 x 10^23', '12.0 x 10^23', 'b', 'เลขอาโวกาโดร (Avogadro''s number) คือค่าคงที่ที่ Nas ต้องจำให้แม่น! 1 โมลของสารใดๆ จะมี 6.02 x 10^23 อนุภาคเสมอ'),

('Chemistry', 'Stoichiometry', 3, 'สารละลายน้ำตาลที่มีความเข้มข้น 2 mol/dm³ จำนวน 500 cm³ จะมีเนื้อน้ำตาลละลายอยู่กี่โมล?', '0.5 mol', '1.0 mol', '2.0 mol', '2.5 mol', '5.0 mol', 'b', 'ใช้สูตร n = CV/1000 จะได้ (2 * 500) / 1000 = 1 โมลครับ Nas! มือนิ่งๆ ค่อยๆ ตัดศูนย์นะเพื่อน'),

('Chemistry', 'Organic Chemistry', 2, 'สารประกอบไฮโดรคาร์บอนประเภทใดที่มี "พันธะคู่" (Double Bond) ระหว่างอะตอมของคาร์บอนอย่างน้อย 1 พันธะ?', 'แอลเคน (Alkane)', 'แอลคีน (Alkene)', 'แอลไคน์ (Alkyne)', 'แอลกอฮอล์', 'กรดอินทรีย์', 'b', 'จำง่ายๆ นะเพื่อน: เคน-เดี่ยว (Single), คีน-คู่ (Double), ไคน์-สาม (Triple) ข้อนี้แอลคีน (Alkene) คือคำตอบที่ถูกต้องครับ'),

('Chemistry', 'Organic Chemistry', 3, 'หมู่ฟังก์ชัน -OH (Hydroxyl group) เป็นหมู่ฟังก์ชันที่แสดงลักษณะเฉพาะของสารอินทรีย์จำพวกใด?', 'อีเทอร์', 'แอลดีไฮด์', 'แอลกอฮอล์', 'เอสเทอร์', 'เอไมด์', 'c', 'ถ้าเห็น -OH ต่อกับสายคาร์บอน ให้รู้เลยว่านี่คือตระกูลแอลกอฮอล์แน่นอน เหมือนเอทานอลที่ใช้เป็นเชื้อเพลิงนั่นแหละ Nas!');
-- เพิ่มโจทย์สอบตรง/โควตา (ไฟฟ้า, เครื่องกล, วัสดุวิศวกรรม)
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Engineering', 'Electrical', 2, 'ในวงจรไฟฟ้ากระแสสลับ (AC) อุปกรณ์ชนิดใดที่ทำหน้าที่ "เก็บสะสมพลังงานในรูปสนามแม่เหล็ก"?', 'ตัวต้านทาน (Resistor)', 'ตัวเก็บประจุ (Capacitor)', 'ตัวเหนี่ยวนำ (Inductor)', 'ไดโอด (Diode)', 'ทรานซิสเตอร์', 'c', 'ตัวเหนี่ยวนำหรือขดลวด (L) จะเก็บพลังงานในรูปสนามแม่เหล็ก ส่วนตัวเก็บประจุ (C) จะเก็บในรูปสนามไฟฟ้านะ Nas!'),

('Engineering', 'Mechanical', 3, 'ในวิชาสถิตยศาสตร์ (Statics) วัตถุที่อยู่ในสภาวะสมดุล (Equilibrium) จะต้องมีลักษณะตามข้อใด?', 'มีความเร่งคงที่', 'ผลรวมของแรงลัพธ์และโมเมนต์ลัพธ์เป็นศูนย์', 'มีความเร็วเพิ่มขึ้นเรื่อยๆ', 'มีแรงกิริยามากกว่าแรงปฏิกิริยา', 'ไม่มีแรงใดๆ มากระทำเลย', 'b', 'จำกฎเหล็กสมดุลไว้ Nas! ΣF = 0 และ ΣM = 0 คือวัตถุต้องไม่เลื่อนที่และไม่หมุนครับ'),

('Engineering', 'Thermodynamics', 3, 'กฎข้อที่หนึ่งของอุณหพลศาสตร์ (First Law of Thermodynamics) คือการประยุกต์ใช้กฎใดในทางฟิสิกส์?', 'กฎการอนุรักษ์โมเมนตัม', 'กฎการอนุรักษ์พลังงาน', 'กฎการอนุรักษ์มวล', 'กฎของนิวตันข้อที่ 2', 'กฎของพาสคัล', 'b', 'เทอร์โมฯ ข้อแรกคือเรื่องพลังงานล้วนๆ Nas! พลังงานความร้อนที่ใส่เข้าไป = พลังงานภายในที่เปลี่ยนไป + งานที่ทำได้ (Q = ΔU + W)'),

('Engineering', 'Materials', 2, 'วัสดุวิศวกรรมในข้อใดที่มีสมบัติ "ความแข็ง (Hardness)" สูงมากแต่ "ความเหนียว (Toughness)" ต่ำ ทำให้เปราะและแตกหักง่าย?', 'เหล็กเหนียว', 'อลูมิเนียม', 'เซรามิก (Ceramics)', 'ทองแดง', 'พลาสติก', 'c', 'เซรามิกแข็งมากแต่เปราะ Nas! เหมือนจานข้าวที่ตกแล้วแตกกระจาย แข็งแต่ไม่ทนแรงกระแทกนั่นเอง'),

('Engineering', 'Manufacturing', 2, 'กระบวนการผลิตใดที่ใช้ในการ "ขึ้นรูปชิ้นส่วนโลหะ" โดยการทำให้ร้อนจนละลายแล้วเทลงในแม่พิมพ์?', 'การกลึง (Turning)', 'การเชื่อม (Welding)', 'การหล่อ (Casting)', 'การกัด (Milling)', 'การปั๊มขึ้นรูป (Stamping)', 'c', 'การหล่อหรือ Casting คือพื้นฐานการทำชิ้นส่วนเครื่องยนต์เลยเพื่อน ละลายเหล็กแล้วเทใส่เบ้า พอเย็นตัวก็ได้รูปทรงที่ต้องการ!');